import React from 'react';

// Filter component: Dropdown or buttons to filter products by category
// Props: categories - array of category names, selectedCategory - current selection, onChange - update function
// This allows users to filter products by category
interface FilterProps {
  categories: string[];
  selectedCategory: string;
  onChange: (category: string) => void;
}

const Filter: React.FC<FilterProps> = ({ categories, selectedCategory, onChange }) => {
  return (
    // Filter container
    <div className="flex flex-wrap gap-2">
      {/* Render button for each category */}
      {categories.map((category) => (
        <button
          key={category}
          onClick={() => onChange(category)}
          className={`px-4 py-2 rounded-lg border transition-colors duration-200 ${
            selectedCategory === category
              ? 'bg-blue-600 text-white border-blue-600' // Active state
              : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50' // Inactive state
          }`}
        >
          {category}
        </button>
      ))}
    </div>
  );
};

export default Filter;
